const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';
const SECRET_KEY = 'NT2026-vapi-s3cur3-k3y';
const N8N_BASE = $env.WEBHOOK_URL || $env.N8N_HOST || '';

const CONSULTORIO = {
  nombre: 'Policonsultorio Rivadavia',
  waNumber: '5491137936325',
  direccion: 'Av. Rivadavia 4520, Piso 1, Caballito, CABA',
  mapsLink: 'https://maps.google.com/?q=Av+Rivadavia+4520+CABA',
  horario: 'Lun-Vie 8:30-19:00, Sab 9:00-13:00',
  telefono: '(011) 4555-1234',
  obrasociales: ['OSDE', 'Swiss Medical', 'Galeno', 'IOMA', 'PAMI', 'Medife', 'Sancor Salud', 'OSECAC', 'OSPEDYC', 'Union Personal'],
  precioParticular: 45000
};
const DIAS = ['Dom','Lun','Mar','Mie','Jue','Vie','Sab'];

async function supaGet(table, params) {
  try {
    return await helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/${table}`,
      qs: params || {},
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
  } catch (e) { return []; }
}

async function supaInsert(table, data) {
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/${table}`,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(data)
    });
  } catch (e) {}
}

async function supaUpdate(table, filters, data) {
  try {
    await helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/${table}`,
      qs: filters,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...data, updated_at: new Date().toISOString() })
    });
  } catch (e) {}
}

async function sendText(phone, text) {
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
    headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ messaging_product: 'whatsapp', to: phone, type: 'text', text: { body: text } })
  });
  if (!resp?.messages?.length) throw new Error('WA send failed: ' + JSON.stringify(resp));
  return resp;
}

async function sendTemplate(phone, templateName, bodyParams) {
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
    headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp',
      to: phone,
      type: 'template',
      template: {
        name: templateName,
        language: { code: 'es_AR' },
        components: [{
          type: 'body',
          parameters: bodyParams.map(t => ({ type: 'text', text: String(t) }))
        }]
      }
    })
  });
  if (!resp?.messages?.length) throw new Error('WA template send failed: ' + JSON.stringify(resp));
  return resp;
}

function formatPhone(phone) {
  if (!phone) return '';
  let p = phone.replace(/[^0-9]/g, '');
  if (p.startsWith('54') && p.length >= 12) return p;
  if (p.startsWith('9') && p.length >= 10) return '54' + p;
  if (p.length === 10) return '549' + p;
  return p;
}

// Meta API Argentina: strip el 9 móvil (5491130875304 → 541130875304)
function formatPhoneWA(phone) {
  let p = formatPhone(phone);
  if (p.startsWith('549') && p.length === 13) p = '54' + p.slice(3);
  return p;
}

function isRealPhone(phone) {
  if (!phone) return false;
  const p = phone.replace(/[^0-9]/g, '');
  if (p.includes('55554050') || p.includes('12345') || p.includes('00000')) return false;
  return p.length >= 10;
}

const body = $input.first().json.body;
const headers_req = $input.first().json.headers;

const authHeader = headers_req?.['x-vapi-secret'] || headers_req?.['X-Vapi-Secret'] || '';
if (authHeader !== SECRET_KEY) {
  return [{ json: { toolCallId: 'unknown', result: 'Error de autenticacion' } }];
}

const message = body?.message;
const toolCallList = message?.toolCallList;
if (!toolCallList?.length) {
  return [{ json: { toolCallId: 'unknown', result: 'No se recibio tool call' } }];
}

const toolCall = toolCallList[0];
const toolCallId = toolCall?.id || '';
const functionName = toolCall?.function?.name || '';
const args = toolCall?.function?.arguments || {};
const customerPhone = message?.call?.customer?.number || '';

try {
  if (functionName === 'consultarInfo') {
    const cat = args.categoria || '';
    if (cat === 'especialidades') {
      const profs = await supaGet('consultorio_profesionales', { activo: 'eq.true', select: 'especialidad', order: 'especialidad.asc' });
      const esps = [...new Set((profs || []).map(p => p.especialidad))];
      return [{ json: { toolCallId, result: `Especialidades disponibles: ${esps.join(', ')}` } }];
    }
    if (cat === 'profesionales') {
      const filters = { activo: 'eq.true', select: 'nombre,especialidad', order: 'especialidad.asc' };
      if (args.especialidad) filters.especialidad = `eq.${args.especialidad}`;
      const profs = await supaGet('consultorio_profesionales', filters);
      if (!profs?.length) return [{ json: { toolCallId, result: 'No encontre profesionales para esa especialidad.' } }];
      const lista = profs.map(p => `${p.nombre} (${p.especialidad})`).join(', ');
      return [{ json: { toolCallId, result: `Profesionales: ${lista}` } }];
    }
    if (cat === 'horarios_profesional') {
      const nombre = args.profesional_nombre || '';
      if (!nombre) return [{ json: { toolCallId, result: 'Necesito el nombre del profesional.' } }];
      const profs = await supaGet('consultorio_profesionales', { activo: 'eq.true', nombre: `ilike.*${nombre}*`, select: 'id,nombre,especialidad,duracion_turno_min' });
      if (!profs?.length) return [{ json: { toolCallId, result: 'No encontre un profesional con ese nombre.' } }];
      const prof = profs[0];
      const horarios = await supaGet('consultorio_horarios_profesional', { profesional_id: `eq.${prof.id}`, select: 'dia_semana,hora_inicio,hora_fin', order: 'dia_semana.asc' });
      if (!horarios?.length) return [{ json: { toolCallId, result: `${prof.nombre} no tiene horarios configurados.` } }];
      const lista = horarios.map(h => `${DIAS[h.dia_semana]} de ${h.hora_inicio.slice(0,5)} a ${h.hora_fin.slice(0,5)}`).join(', ');
      return [{ json: { toolCallId, result: `${prof.nombre} (${prof.especialidad}) atiende: ${lista}. Turnos de ${prof.duracion_turno_min} minutos.` } }];
    }
    if (cat === 'obras_sociales') return [{ json: { toolCallId, result: `Obras sociales: ${CONSULTORIO.obrasociales.join(', ')}` } }];
    if (cat === 'direccion') return [{ json: { toolCallId, result: `${CONSULTORIO.nombre}, ${CONSULTORIO.direccion}. Tel: ${CONSULTORIO.telefono}` } }];
    if (cat === 'horario_general') return [{ json: { toolCallId, result: `Horario: ${CONSULTORIO.horario}` } }];
    if (cat === 'precios') return [{ json: { toolCallId, result: `Consulta particular: $${CONSULTORIO.precioParticular.toLocaleString('es-AR')}` } }];
    return [{ json: { toolCallId, result: 'Categoria no reconocida.' } }];
  }

  if (functionName === 'consultarTurnosPaciente') {
    const dni = (args.dni || '').replace(/\./g, '').trim();
    if (!dni || dni.length < 7) return [{ json: { toolCallId, result: 'DNI no valido. Debe tener al menos 7 digitos.' } }];
    const pacientes = await supaGet('consultorio_pacientes', { dni: `eq.${dni}`, select: 'id,nombre' });
    if (!pacientes?.length) return [{ json: { toolCallId, result: `No encontre paciente con DNI ${dni}.` } }];
    const pac = pacientes[0];
    const turnos = await supaGet('consultorio_turnos', { paciente_id: `eq.${pac.id}`, estado: 'in.(agendado,confirmado)', select: 'fecha_hora,estado,profesional_id', order: 'fecha_hora.asc' });
    if (!turnos?.length) return [{ json: { toolCallId, result: `${pac.nombre}, no tenes turnos pendientes.` } }];
    const profIds = [...new Set(turnos.map(t => t.profesional_id))];
    const profs = await supaGet('consultorio_profesionales', { id: `in.(${profIds.join(',')})`, select: 'id,nombre,especialidad' });
    const profMap = {};
    (profs || []).forEach(p => { profMap[p.id] = p; });
    const lista = turnos.map(t => {
      const f = new Date(t.fecha_hora);
      const prof = profMap[t.profesional_id] || {};
      return `${f.getDate()}/${f.getMonth()+1} a las ${f.getHours()}:${String(f.getMinutes()).padStart(2,'0')} con ${prof.nombre || 'profesional'} (${prof.especialidad || ''})`;
    }).join('. ');
    return [{ json: { toolCallId, result: `${pac.nombre}, tus turnos: ${lista}` } }];
  }

  if (functionName === 'enviarWhatsAppBooking') {
    let tel = '';
    if (isRealPhone(customerPhone)) tel = customerPhone;
    else if (isRealPhone(args.telefono)) tel = args.telefono;
    if (!tel) return [{ json: { toolCallId, result: 'No pude obtener el numero.' } }];
    const waPhone = formatPhone(tel);      // para Supabase lookup (con 9)
    const waPhoneSend = formatPhone(tel);  // para Meta WhatsApp API (con 9)
    const nombre = args.nombre_paciente || '';
    const especialidad = args.especialidad || '';
    const primerNombre = nombre ? nombre.split(' ')[0] : 'Paciente';
    const espDisplay = especialidad || 'tu consulta';
    const tmplResp = await sendTemplate(waPhoneSend, 'turno_booking', [primerNombre, espDisplay]);
    const waId = tmplResp?.contacts?.[0]?.wa_id || waPhoneSend;
    // Upsert contexto para WF02
    const existing = await supaGet('consultorio_conversaciones', { telefono_wa: `eq.${waPhone}`, select: 'id' });
    const vapiCtx = { from_vapi: true, nombre_sugerido: nombre, especialidad_sugerida: especialidad };
    if (existing?.length) {
      await supaUpdate('consultorio_conversaciones', { telefono_wa: `eq.${waPhone}` },
        { estado: 'inicio', contexto: vapiCtx, handoff_humano: false });
    } else {
      await supaInsert('consultorio_conversaciones',
        { telefono_wa: waPhone, estado: 'inicio', contexto: vapiCtx, handoff_humano: false });
    }
    return [{ json: { toolCallId, result: 'WhatsApp enviado correctamente.', debug_waId: waId, debug_sendPhone: waPhoneSend, debug_metaResp: tmplResp } }];
  }

  if (functionName === 'enviarWhatsAppCancelacion') {
    let tel = '';
    if (isRealPhone(customerPhone)) tel = customerPhone;
    else if (isRealPhone(args.telefono)) tel = args.telefono;
    if (!tel) return [{ json: { toolCallId, result: 'No pude obtener el numero.' } }];
    const waPhone = formatPhone(tel);
    const waPhoneSend = formatPhone(tel);  // con 9 móvil para WhatsApp
    const nombre = args.nombre_paciente || '';
    const medico = args.medico_nombre || 'tu médico';
    const primerNombre = nombre ? nombre.split(' ')[0] : 'Paciente';
    await sendTemplate(waPhoneSend, 'turno_cancelacion', [primerNombre, medico]);
    return [{ json: { toolCallId, result: 'WhatsApp enviado para cancelacion.' } }];
  }

  if (functionName === 'consultarDisponibilidad') {
    const nombre = args.profesional_nombre || '';
    const especialidad = args.especialidad || '';
    const allProfs = await supaGet('consultorio_profesionales', { activo: 'eq.true', select: 'id,nombre,especialidad,duracion_turno_min' });
    const norm = s => s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    let profs = allProfs || [];
    if (nombre) profs = profs.filter(p => norm(p.nombre).includes(norm(nombre)));
    else if (especialidad) profs = profs.filter(p => norm(p.especialidad) === norm(especialidad));
    if (!profs?.length) return [{ json: { toolCallId, result: 'No encontré ese profesional o especialidad.' } }];
    const prof = profs[0];
    const horarios = await supaGet('consultorio_horarios_profesional', {
      profesional_id: `eq.${prof.id}`, select: 'dia_semana,hora_inicio,hora_fin', order: 'dia_semana.asc'
    });
    if (!horarios?.length) return [{ json: { toolCallId, result: `${prof.nombre} no tiene agenda configurada todavía.` } }];
    const diasNombre = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
    const lista = horarios.map(h => `${diasNombre[h.dia_semana]} de ${h.hora_inicio.slice(0,5)} a ${h.hora_fin.slice(0,5)}`).join(', ');
    return [{ json: { toolCallId, result: `${prof.nombre} (${prof.especialidad}) atiende ${lista}. Hay turnos disponibles. ¿Querés que te mande un WhatsApp para que elijas el horario que más te convenga?` } }];
  }

  return [{ json: { toolCallId, result: `Tool ${functionName} no reconocida.` } }];

} catch (error) {
  return [{ json: { toolCallId, result: `Error: ${error.message}` } }];
}

